def validate(args, output):
    nums = args[0]
    n = len(nums)
    if not isinstance(output, bool) and isinstance(output, int):
        i = output
    else:
        return False
    if i < 0 or i >= n:
        return False
    left = nums[i - 1] if i - 1 >= 0 else None
    right = nums[i + 1] if i + 1 < n else None
    if left is not None and not (nums[i] > left):
        return False
    if right is not None and not (nums[i] > right):
        return False
    return True

