function validate(args, output) {
    const nums = args[0];
    const n = nums.length;
    if (typeof output !== 'number' || !Number.isInteger(output)) return false;
    const i = output;
    if (i < 0 || i >= n) return false;
    if (i - 1 >= 0 && !(nums[i] > nums[i - 1])) return false;
    if (i + 1 < n && !(nums[i] > nums[i + 1])) return false;
    return true;
}

